const USD = new Intl.NumberFormat('en-US', {style:'currency', currency:'USD', maximumFractionDigits:0});
const PCT = new Intl.NumberFormat('en-US', {style:'percent', minimumFractionDigits:1, maximumFractionDigits:1});
const NUM1 = new Intl.NumberFormat('en-US', {minimumFractionDigits:1, maximumFractionDigits:1});
const NUM2 = new Intl.NumberFormat('en-US', {minimumFractionDigits:2, maximumFractionDigits:2});

let CURRENT_SCENARIO = 'base';
let CURRENT_TAB = 'income_statement';
let CUSTOM_STATE = {};

function init() {
  buildInputGrid();
  bindEvents();
  resetCustomState();
  renderScenario('base');
}

function bindEvents() {
  document.getElementById('scenarioSelect').addEventListener('change', e => {
    const scen = e.target.value;
    document.getElementById('customPanel').classList.toggle('hidden', scen !== 'custom');
    if (scen === 'custom') renderScenario('custom');
    else renderScenario(scen);
  });

  document.getElementById('compareSelect').addEventListener('change', () => renderScenario(CURRENT_SCENARIO));
  document.getElementById('applyCustomBtn').addEventListener('click', () => {
    readInputsIntoCustomState();
    renderScenario('custom');
  });
  document.getElementById('resetCustomBtn').addEventListener('click', () => {
    resetCustomState();
    if (CURRENT_SCENARIO === 'custom') renderScenario('custom');
  });
  document.getElementById('fillStrainBtn').addEventListener('click', () => {
    resetCustomState();
    [2026,2027,2028].forEach(y => {
      setInputValue('InterestRate', y, (Number(DATA.baseAssumptions[String(y)].InterestRate) + 0.015));
      setInputValue('EBITDA_Margin', y, (Number(DATA.baseAssumptions[String(y)].EBITDA_Margin) - 0.002));
      setInputValue('CashFloor', y, (Number(DATA.baseAssumptions[String(y)].CashFloor) + 2000000000));
      setInputValue('ExcessCashSweepPct', y, Math.max(Number(DATA.baseAssumptions[String(y)].ExcessCashSweepPct) - 0.20, 0));
    });
    readInputsIntoCustomState();
    renderScenario('custom');
  });

  document.querySelectorAll('.tab').forEach(btn => btn.addEventListener('click', e => {
    document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
    e.target.classList.add('active');
    CURRENT_TAB = e.target.dataset.tab;
    renderScenario(CURRENT_SCENARIO);
  }));
}

function buildInputGrid() {
  const grid = document.getElementById('inputGrid');
  const years = DATA.forecastYears;
  Object.entries(DATA.inputSchema).forEach(([key, cfg]) => {
    const row = document.createElement('div');
    row.className = 'contract-row';
    const name = document.createElement('div');
    name.className = 'name';
    name.innerHTML = `<strong>${cfg.label}</strong><div class="mini">${formatRange(cfg.min, cfg.max, key)}</div>`;
    row.appendChild(name);
    years.forEach(year => {
      const cell = document.createElement('div');
      const input = document.createElement('input');
      input.type = 'number';
      input.step = key === 'CashFloor' ? '100000000' : '0.001';
      input.min = cfg.min;
      input.max = cfg.max;
      input.dataset.key = key;
      input.dataset.year = year;
      input.placeholder = displayInputValue(DATA.baseAssumptions[String(year)][key], key);
      cell.appendChild(input);
      row.appendChild(cell);
    });
    grid.appendChild(row);
  });
}

function resetCustomState() {
  CUSTOM_STATE = {};
  document.querySelectorAll('#inputGrid input').forEach(inp => inp.value = '');
}

function setInputValue(key, year, value) {
  const el = document.querySelector(`#inputGrid input[data-key="${key}"][data-year="${year}"]`);
  if (el) el.value = Number(value);
}

function readInputsIntoCustomState() {
  CUSTOM_STATE = {};
  document.querySelectorAll('#inputGrid input').forEach(inp => {
    if (inp.value === '') return;
    const key = inp.dataset.key, year = inp.dataset.year;
    if (!CUSTOM_STATE[key]) CUSTOM_STATE[key] = {};
    CUSTOM_STATE[key][year] = Number(inp.value);
  });
}

function formatRange(min, max, key) {
  if (key === 'CashFloor') return `Allowed: ${fmtB(min)} to ${fmtB(max)}`;
  return `Allowed: ${PCT.format(min)} to ${PCT.format(max)}`;
}

function displayInputValue(v, key) {
  return key === 'CashFloor' ? fmtB(v) : (v * 100).toFixed(1) + '%';
}

function fmtB(value) {
  return '$' + NUM1.format(value / 1e9) + 'B';
}

function fmtPct(v) { return (v * 100).toFixed(1) + '%'; }

function deriveScenarioData(scenario) {
  if (scenario !== 'custom') {
    const rows = DATA.storedForecast.filter(r => r.Scenario === scenario).map(normalizeRecord);
    return {
      scenario,
      rows,
      diag: DATA.storedDiagnostics.filter(r => r.Scenario === scenario),
      meta: DATA.storedManifest.find(r => r.Scenario === scenario) || null,
      notes: (DATA.storedMeta.find(r => r.Scenario === scenario) || {}).ScenarioNotes || '',
      assumptions: buildStoredAssumptionsTable(scenario),
      statementRows: buildStatementRowsFromStored(scenario)
    };
  }
  const path = materializeScenario('custom', CUSTOM_STATE);
  const rows = runModel(path, 'custom', 'Browser-side custom scenario using the notebook input contract.');
  const diag = rows.map(r => ({
    Scenario: 'custom',
    Year: r.Year,
    RunID: r.RunID,
    BalanceSheetTieDelta: r.BalanceSheetTieDelta,
    CashFlowTieDelta: r.CashFlowTieDelta,
    PPE_RollForward_Check: r.PPE_RollForward_Check,
    Debt_RollForward_Check: r.Debt_RollForward_Check,
    RetainedEarnings_RollForward_Check: r.RetainedEarnings_RollForward_Check,
    OtherLiabilities_PctRevenue: r.OtherLiabilities_PctRevenue,
    DiagnosticStatus: r.DiagnosticStatus
  }));
  const status = diag.every(r => r.DiagnosticStatus === 'PASS') ? 'PASS' : (diag.some(r => r.DiagnosticStatus === 'FAIL') ? 'FAIL' : 'WARN');
  return {
    scenario,
    rows,
    diag,
    meta: {
      Scenario: 'custom',
      RunID: 'BROWSER_CUSTOM',
      Company: DATA.company,
      ModelVersion: 'browser_js_v1',
      DataVersion: 'official_csv_outputs + annual_historical_bundle.csv',
      MinYear: 2026,
      MaxYear: 2028,
      OverallDiagnosticStatus: status,
      ExportBundleReference: 'browser_custom',
      DashboardScenarioRequest: 'custom'
    },
    notes: 'Multiple year-by-year overrides can be layered together in custom mode.',
    assumptions: buildCustomAssumptionsTable(path),
    statementRows: buildStatementRowsFromComputed(rows)
  };
}

function materializeScenario(name, customOverrides = {}) {
  const path = deepClone(DATA.baseAssumptions);

  if (name === 'downside') {
    ["MobilityGrowth","BusinessWirelineGrowth","ConsumerWirelineGrowth","LatinAmericaGrowth","OtherRevenueGrowth"].forEach(col => {
      DATA.forecastYears.forEach(y => path[y][col] -= 0.05);
    });
    DATA.forecastYears.forEach(y => {
      path[y].EBITDA_Margin -= 0.012;
      path[y].COGS_PctRevenue += 0.006;
      path[y].SGA_PctRevenue += 0.003;
      path[y].Capex_PctRevenue -= 0.005;
      path[y].DSO += 1.5;
      path[y].DIO += 1.0;
      path[y].DPO -= 3.0;
      path[y].InterestRate += 0.003;
      path[y].DebtAmortizationPct = Math.max(path[y].DebtAmortizationPct - 0.005, 0);
      path[y].ExcessCashSweepPct = Math.max(path[y].ExcessCashSweepPct - 0.10, 0);
    });
  } else if (name === 'upside') {
    ["MobilityGrowth","BusinessWirelineGrowth","ConsumerWirelineGrowth","LatinAmericaGrowth","OtherRevenueGrowth"].forEach(col => {
      DATA.forecastYears.forEach(y => path[y][col] += 0.05);
    });
    DATA.forecastYears.forEach(y => {
      path[y].EBITDA_Margin += 0.010;
      path[y].COGS_PctRevenue -= 0.005;
      path[y].SGA_PctRevenue -= 0.002;
      path[y].Capex_PctRevenue += 0.003;
      path[y].DSO -= 1.0;
      path[y].DIO -= 0.5;
      path[y].DPO += 2.0;
      path[y].InterestRate -= 0.002;
      path[y].DebtAmortizationPct += 0.005;
      path[y].ExcessCashSweepPct = Math.min(path[y].ExcessCashSweepPct + 0.10, 1);
    });
  } else if (name === 'energy_cost_strain') {
    DATA.forecastYears.forEach(y => {
      path[y].EBITDA_Margin -= 0.018;
      path[y].COGS_PctRevenue += 0.010;
      path[y].SGA_PctRevenue += 0.004;
      path[y].Capex_PctRevenue += 0.002;
      path[y].ExcessCashSweepPct = Math.max(path[y].ExcessCashSweepPct - 0.15, 0);
    });
  } else if (name === 'interest_rate_strain') {
    DATA.forecastYears.forEach(y => {
      path[y].InterestRate += 0.015;
      path[y].EBITDA_Margin -= 0.002;
      path[y].CashFloor += 2e9;
      path[y].ExcessCashSweepPct = Math.max(path[y].ExcessCashSweepPct - 0.20, 0);
    });
  }

  Object.entries(customOverrides || {}).forEach(([key, yearDict]) => {
    Object.entries(yearDict).forEach(([year, value]) => {
      if (path[year] && path[year][key] !== undefined) path[year][key] = Number(value);
    });
  });
  return path;
}

function runModel(path, scenarioLabel, notes) {
  const rows = [];
  let prevSegments = deepClone(DATA.segmentStart);
  let prevCash = Number(DATA.opening.Cash);
  let prevAR = Number(DATA.opening.AR);
  let prevInventory = Number(DATA.opening.Inventory);
  let prevAP = Number(DATA.opening.AP);
  let prevTotalDebt = Number(DATA.opening.TotalDebt);
  let prevPPE = Number(DATA.opening.NetPPE);
  let prevRE = Number(DATA.opening.RetainedEarnings);
  let prevOtherCA = Number(DATA.opening.OtherCurrentAssets);
  let prevGoodwill = Number(DATA.opening.GoodwillIntangibles);
  let prevOtherNCA = Number(DATA.opening.OtherNonCurrentAssets);
  const openingEquityConstant = Number(DATA.opening.Equity) - Number(DATA.opening.RetainedEarnings);
  const years = DATA.forecastYears;

  years.forEach(year => {
    const a = path[String(year)] || path[year];

    const mobility = prevSegments.MobilityRevenue * (1 + Number(a.MobilityGrowth));
    const businessWireline = prevSegments.BusinessWirelineRevenue * (1 + Number(a.BusinessWirelineGrowth));
    const consumerWireline = prevSegments.ConsumerWirelineRevenue * (1 + Number(a.ConsumerWirelineGrowth));
    const latinAmerica = prevSegments.LatinAmericaRevenue * (1 + Number(a.LatinAmericaGrowth));
    const otherRevenue = prevSegments.OtherRevenue * (1 + Number(a.OtherRevenueGrowth));
    const revenue = mobility + businessWireline + consumerWireline + latinAmerica + otherRevenue;

    const cogs = revenue * Number(a.COGS_PctRevenue);
    const grossProfit = revenue - cogs;
    const sga = revenue * Number(a.SGA_PctRevenue);
    const ebitda = revenue * Number(a.EBITDA_Margin);
    const dandA = revenue * Number(a.DandA_PctRevenue);
    const otherOpEx = grossProfit - sga - ebitda;
    const ebit = ebitda - dandA;

    const ar = revenue * Number(a.DSO) / 365.0;
    const inventory = cogs * Number(a.DIO) / 365.0;
    const otherCurrentAssets = revenue * Number(a.OtherCurrentAssets_PctRevenue);
    const ap = cogs * Number(a.DPO) / 365.0;

    const deltaWC = (ar - prevAR) + (inventory - prevInventory) + (otherCurrentAssets - prevOtherCA) - (ap - prevAP);

    const capex = revenue * Number(a.Capex_PctRevenue);
    const ppe = prevPPE + capex - dandA;
    const goodwill = prevGoodwill * 0.99;
    const otherNCA = prevOtherNCA * 0.995;

    const beginningDebt = prevTotalDebt;
    const cashFloor = Number(a.CashFloor);
    const debtAmortPct = Number(a.DebtAmortizationPct);
    const excessCashSweepPct = Number(a.ExcessCashSweepPct);
    let endingDebtGuess = beginningDebt;

    for (let i=0;i<5;i++) {
      const averageDebt = (beginningDebt + endingDebtGuess) / 2;
      const interestExpense = averageDebt * Number(a.InterestRate);
      const pretaxIncome = ebit - interestExpense;
      const taxes = Math.max(pretaxIncome, 0) * Number(a.TaxRate);
      const netIncome = pretaxIncome - taxes;
      const dividends = Math.max(netIncome, 0) * Number(a.DividendPayoutRatio);
      const cfo = netIncome + dandA - deltaWC;
      const cfi = -capex;

      const mandatoryRepayment = Math.min(beginningDebt * debtAmortPct, beginningDebt);
      const cashAfterOpsInvDiv = prevCash + cfo + cfi - dividends;
      const cashAfterMandatory = cashAfterOpsInvDiv - mandatoryRepayment;

      const newBorrowing = Math.max(cashFloor - cashAfterMandatory, 0);
      const excessCashPreSweep = Math.max(cashAfterMandatory - cashFloor, 0);
      const optionalRepaymentCapacity = Math.max(beginningDebt - mandatoryRepayment, 0);
      const optionalRepayment = Math.min(excessCashPreSweep * excessCashSweepPct, optionalRepaymentCapacity);

      const endingDebt = Math.max(beginningDebt - mandatoryRepayment - optionalRepayment + newBorrowing, 0);
      if (Math.abs(endingDebt - endingDebtGuess) < 1) {
        endingDebtGuess = endingDebt;
        break;
      }
      endingDebtGuess = endingDebt;
    }

    const totalDebt = endingDebtGuess;
    const averageDebt = (beginningDebt + totalDebt) / 2;
    const interestExpense = averageDebt * Number(a.InterestRate);
    const pretaxIncome = ebit - interestExpense;
    const taxes = Math.max(pretaxIncome, 0) * Number(a.TaxRate);
    const netIncome = pretaxIncome - taxes;
    const dividends = Math.max(netIncome, 0) * Number(a.DividendPayoutRatio);
    const cfo = netIncome + dandA - deltaWC;
    const cfi = -capex;
    const mandatoryRepayment = Math.min(beginningDebt * debtAmortPct, beginningDebt);
    const cashAfterOpsInvDiv = prevCash + cfo + cfi - dividends;
    const cashAfterMandatory = cashAfterOpsInvDiv - mandatoryRepayment;
    const newBorrowing = Math.max(cashFloor - cashAfterMandatory, 0);
    const excessCashPreSweep = Math.max(cashAfterMandatory - cashFloor, 0);
    const optionalRepaymentCapacity = Math.max(beginningDebt - mandatoryRepayment, 0);
    const optionalRepayment = Math.min(excessCashPreSweep * excessCashSweepPct, optionalRepaymentCapacity);
    const finalDebt = Math.max(beginningDebt - mandatoryRepayment - optionalRepayment + newBorrowing, 0);
    const shortDebt = finalDebt * Number(a.TargetShortDebtShare);
    const longDebt = finalDebt - shortDebt;
    const cff = newBorrowing - mandatoryRepayment - optionalRepayment - dividends;
    const cash = prevCash + cfo + cfi + cff;

    const retainedEarnings = prevRE + netIncome - dividends;
    const equity = openingEquityConstant + retainedEarnings;

    const totalAssets = cash + ar + inventory + otherCurrentAssets + ppe + goodwill + otherNCA;
    const otherLiabilities = totalAssets - ap - finalDebt - equity;
    const totalLiabilities = ap + finalDebt + otherLiabilities;

    const bsTie = totalAssets - (totalLiabilities + equity);
    const cfTie = cfo + cfi + cff - (cash - prevCash);
    const ppeTie = (prevPPE + capex - dandA) - ppe;
    const debtTie = (beginningDebt - mandatoryRepayment - optionalRepayment + newBorrowing) - finalDebt;
    const reTie = (prevRE + netIncome - dividends) - retainedEarnings;

    let diagnosticStatus = 'FAIL';
    if ([bsTie,cfTie,ppeTie,debtTie,reTie].every(v => Math.abs(v) < 1)) diagnosticStatus = 'PASS';
    else if (Math.max(...[bsTie,cfTie,ppeTie,debtTie,reTie].map(v => Math.abs(v))) < 1e6) diagnosticStatus = 'WARN';

    rows.push(normalizeRecord({
      Company: DATA.company,
      Scenario: scenarioLabel,
      RunID: 'BROWSER_CUSTOM',
      ModelVersion: 'browser_js_v1',
      DataVersion: 'derived from official csv outputs',
      ScenarioNotes: notes,
      Year: year,
      Units: 'USD',
      MobilityRevenue: mobility,
      BusinessWirelineRevenue: businessWireline,
      ConsumerWirelineRevenue: consumerWireline,
      LatinAmericaRevenue: latinAmerica,
      OtherRevenue: otherRevenue,
      Revenue: revenue,
      COGS: cogs,
      GrossProfit: grossProfit,
      'SG&A': sga,
      OtherOpEx: otherOpEx,
      EBITDA: ebitda,
      'D&A': dandA,
      EBIT: ebit,
      BeginningDebt: beginningDebt,
      AvgDebt: averageDebt,
      InterestRateApplied: Number(a.InterestRate),
      InterestExpense: interestExpense,
      PretaxIncome: pretaxIncome,
      Taxes: taxes,
      NetIncome: netIncome,
      ChangeInWorkingCapital: -deltaWC,
      CFO: cfo,
      Capex: capex,
      CFI: cfi,
      MandatoryDebtRepayment: mandatoryRepayment,
      OptionalDebtRepayment: optionalRepayment,
      NewBorrowing: newBorrowing,
      NetDebtIssuance: newBorrowing - mandatoryRepayment - optionalRepayment,
      Dividends: dividends,
      CFF: cff,
      DeltaCash: cash - prevCash,
      Cash: cash,
      AR: ar,
      Inventory: inventory,
      OtherCurrentAssets: otherCurrentAssets,
      NetPPE: ppe,
      GoodwillIntangibles: goodwill,
      OtherNonCurrentAssets: otherNCA,
      TotalAssets: totalAssets,
      AP: ap,
      ShortTermDebt: shortDebt,
      LongTermDebt: longDebt,
      TotalDebt: finalDebt,
      OtherLiabilities: otherLiabilities,
      TotalLiabilities: totalLiabilities,
      RetainedEarnings: retainedEarnings,
      Equity: equity,
      TotalLiabilitiesAndEquity: totalLiabilities + equity,
      BalanceSheetTieDelta: bsTie,
      CashFlowTieDelta: cfTie,
      PPE_RollForward_Check: ppeTie,
      Debt_RollForward_Check: debtTie,
      RetainedEarnings_RollForward_Check: reTie,
      OtherLiabilities_PctRevenue: revenue ? otherLiabilities / revenue : null,
      EBITDA_Margin: revenue ? ebitda / revenue : null,
      CFO_Margin: revenue ? cfo / revenue : null,
      NetDebt_to_EBITDA: ebitda ? Math.max(finalDebt - cash, 0) / ebitda : null,
      DiagnosticStatus: diagnosticStatus
    }));

    prevSegments = {MobilityRevenue: mobility, BusinessWirelineRevenue: businessWireline, ConsumerWirelineRevenue: consumerWireline, LatinAmericaRevenue: latinAmerica, OtherRevenue: otherRevenue};
    prevCash = cash; prevAR = ar; prevInventory = inventory; prevAP = ap; prevTotalDebt = finalDebt; prevPPE = ppe; prevRE = retainedEarnings;
    prevOtherCA = otherCurrentAssets; prevGoodwill = goodwill; prevOtherNCA = otherNCA;
  });

  return rows;
}

function normalizeRecord(row) {
  Object.keys(row).forEach(k => {
    if (typeof row[k] === 'string' && row[k] !== '' && !isNaN(row[k])) row[k] = Number(row[k]);
  });
  return row;
}

function buildStoredAssumptionsTable(scenario) {
  const rows = [];
  const data = DATA.storedAssumptions[scenario];
  Object.keys(data).forEach(year => {
    Object.entries(data[year]).forEach(([name, value]) => rows.push({Year: Number(year), Assumption: name, Value: value}));
  });
  return rows;
}

function buildCustomAssumptionsTable(path) {
  const rows = [];
  Object.keys(path).forEach(year => {
    Object.entries(path[year]).forEach(([name, value]) => rows.push({Year: Number(year), Assumption: name, Value: value}));
  });
  return rows;
}

function buildStatementRowsFromStored(scenario) {
  return DATA.storedStatements.filter(r => r.Scenario === scenario);
}

function buildStatementRowsFromComputed(rows) {
  const map = {
    income_statement: ['Revenue','COGS','GrossProfit','SG&A','OtherOpEx','EBITDA','D&A','EBIT','InterestExpense','PretaxIncome','Taxes','NetIncome'],
    balance_sheet: ['Cash','AR','Inventory','OtherCurrentAssets','NetPPE','GoodwillIntangibles','OtherNonCurrentAssets','TotalAssets','AP','ShortTermDebt','LongTermDebt','TotalDebt','OtherLiabilities','TotalLiabilities','RetainedEarnings','Equity','TotalLiabilitiesAndEquity'],
    cash_flow: ['NetIncome','D&A','ChangeInWorkingCapital','CFO','Capex','CFI','NetDebtIssuance','Dividends','CFF','DeltaCash','Cash']
  };
  const out = [];
  rows.forEach(r => {
    Object.entries(map).forEach(([statement, items]) => {
      items.forEach(item => out.push({
        RunID: r.RunID,
        Scenario: r.Scenario,
        Statement: statement,
        LineItem: item,
        Year: r.Year,
        Value_BillionsUSD: (Number(r[item]) || 0) / 1e9
      }));
    });
  });
  return out;
}

function renderScenario(scenario) {
  CURRENT_SCENARIO = scenario;
  const bundle = deriveScenarioData(scenario);
  renderHeader(bundle);
  renderKpis(bundle);
  renderTrend(bundle);
  renderCompare(bundle);
  renderStatementTable(bundle);
  renderRunMeta(bundle);
  renderDiagnostics(bundle);
}

function renderHeader(bundle) {
  const status = bundle.meta?.OverallDiagnosticStatus || (bundle.diag.every(r => r.DiagnosticStatus === 'PASS') ? 'PASS' : 'WARN');
  const statusBadge = document.getElementById('statusBadge');
  statusBadge.textContent = `${bundle.scenario.toUpperCase()} • ${status}`;
  statusBadge.className = `badge ${statusClass(status)}`;
  document.getElementById('scenarioMeta').innerHTML =
    `<strong>Run reference:</strong> ${bundle.meta?.RunID || 'BROWSER_CUSTOM'}<br>` +
    `<strong>Notes:</strong> ${bundle.notes || '—'}`;
}

function renderKpis(bundle) {
  const finalRow = bundle.rows[bundle.rows.length - 1];
  const prevRow = bundle.rows[bundle.rows.length - 2] || bundle.rows[0];
  const kpis = [
    ['Revenue', fmtB(finalRow.Revenue), changeSub(finalRow.Revenue, prevRow.Revenue)],
    ['EBITDA', fmtB(finalRow.EBITDA), changeSub(finalRow.EBITDA, prevRow.EBITDA)],
    ['Net income', fmtB(finalRow.NetIncome), changeSub(finalRow.NetIncome, prevRow.NetIncome)],
    ['Cash from ops', fmtB(finalRow.CFO), changeSub(finalRow.CFO, prevRow.CFO)],
    ['Ending cash', fmtB(finalRow.Cash), changeSub(finalRow.Cash, prevRow.Cash)],
    ['Net debt / EBITDA', NUM2.format(finalRow.NetDebt_to_EBITDA) + 'x', `2028 diagnostic: ${finalRow.DiagnosticStatus}`],
  ];
  document.getElementById('kpis').innerHTML = kpis.map(([label,value,sub]) =>
    `<div class="kpi"><div class="label">${label}</div><div class="value">${value}</div><div class="sub">${sub}</div></div>`
  ).join('');
}

function renderTrend(bundle) {
  const years = DATA.historical.map(r => r.Year).concat(bundle.rows.map(r => r.Year));
  const hist = DATA.historical;
  const trace1 = {x: hist.map(r=>r.Year), y: hist.map(r=>r.Revenue/1e9), name:'Historical Revenue', mode:'lines+markers'};
  const trace2 = {x: bundle.rows.map(r=>r.Year), y: bundle.rows.map(r=>r.Revenue/1e9), name:`${bundle.scenario} Revenue`, mode:'lines+markers'};
  const trace3 = {x: bundle.rows.map(r=>r.Year), y: bundle.rows.map(r=>r.EBITDA/1e9), name:`${bundle.scenario} EBITDA`, mode:'lines+markers'};
  const trace4 = {x: bundle.rows.map(r=>r.Year), y: bundle.rows.map(r=>r.CFO/1e9), name:`${bundle.scenario} CFO`, mode:'lines+markers'};
  Plotly.newPlot('trendChart', [trace1, trace2, trace3, trace4], chartLayout('USD billions'));
}

function renderCompare(bundle) {
  const compareMode = document.getElementById('compareSelect').value;
  let rows = [];
  if (compareMode === 'base') {
    rows = [
      DATA.storedForecast.find(r => r.Scenario === 'base' && Number(r.Year) === 2028),
      bundle.rows.find(r => Number(r.Year) === 2028)
    ].filter(Boolean);
  } else {
    const stored = ['base','downside','upside','energy_cost_strain','interest_rate_strain']
      .map(s => DATA.storedForecast.find(r => r.Scenario === s && Number(r.Year) === 2028))
      .filter(Boolean)
      .map(normalizeRecord);
    if (bundle.scenario === 'custom') stored.push(bundle.rows.find(r => Number(r.Year) === 2028));
    rows = stored;
  }
  const x = rows.map(r => r.Scenario);
  const t1 = {x, y: rows.map(r => r.Revenue/1e9), type:'bar', name:'Revenue'};
  const t2 = {x, y: rows.map(r => r.EBITDA/1e9), type:'bar', name:'EBITDA'};
  Plotly.newPlot('compareChart', [t1,t2], chartLayout('2028 USD billions', true));
}

function renderStatementTable(bundle) {
  let html = '<table><thead><tr>';
  if (CURRENT_TAB === 'assumptions') {
    html += '<th>Year</th><th>Assumption</th><th>Value</th></tr></thead><tbody>';
    bundle.assumptions.forEach(r => {
      const isPct = !['CashFloor','DSO','DIO','DPO'].includes(r.Assumption);
      html += `<tr><td>${r.Year}</td><td>${r.Assumption}</td><td>${formatAssumptionValue(r.Value, r.Assumption, isPct)}</td></tr>`;
    });
  } else {
    const statementRows = bundle.statementRows.filter(r => r.Statement === CURRENT_TAB);
    const years = [...new Set(statementRows.map(r => Number(r.Year)))];
    const items = [...new Set(statementRows.map(r => r.LineItem))];
    html += '<th>Line item</th>' + years.map(y => `<th>${y}</th>`).join('') + '</tr></thead><tbody>';
    items.forEach(item => {
      html += `<tr><td>${item}</td>`;
      years.forEach(y => {
        const rec = statementRows.find(r => r.LineItem === item && Number(r.Year) === y);
        html += `<td>${rec ? '$' + NUM2.format(Number(rec.Value_BillionsUSD)) + 'B' : '—'}</td>`;
      });
      html += '</tr>';
    });
  }
  html += '</tbody></table>';
  document.getElementById('statementTable').innerHTML = html;
}

function renderRunMeta(bundle) {
  const m = bundle.meta || {};
  const html = `<table><tbody>
    <tr><th>Company</th><td>${m.Company || DATA.company}</td></tr>
    <tr><th>Scenario</th><td>${m.Scenario || bundle.scenario}</td></tr>
    <tr><th>Run ID</th><td>${m.RunID || 'BROWSER_CUSTOM'}</td></tr>
    <tr><th>Model version</th><td>${m.ModelVersion || 'browser_js_v1'}</td></tr>
    <tr><th>Data version</th><td>${m.DataVersion || 'official outputs'}</td></tr>
    <tr><th>Diagnostic status</th><td class="${statusClass(m.OverallDiagnosticStatus || 'PASS')}">${m.OverallDiagnosticStatus || 'PASS'}</td></tr>
  </tbody></table>`;
  document.getElementById('runMetaTable').innerHTML = html;
}

function renderDiagnostics(bundle) {
  const html = '<table><thead><tr><th>Year</th><th>Status</th><th>BS tie</th><th>CF tie</th><th>Debt roll</th><th>RE roll</th></tr></thead><tbody>' +
    bundle.diag.map(r => `<tr>
      <td>${r.Year}</td>
      <td class="${statusClass(r.DiagnosticStatus)}">${r.DiagnosticStatus}</td>
      <td>${NUM2.format(Number(r.BalanceSheetTieDelta||0))}</td>
      <td>${NUM2.format(Number(r.CashFlowTieDelta||0))}</td>
      <td>${NUM2.format(Number(r.Debt_RollForward_Check||0))}</td>
      <td>${NUM2.format(Number(r.RetainedEarnings_RollForward_Check||0))}</td>
    </tr>`).join('') + '</tbody></table>';
  document.getElementById('diagTable').innerHTML = html;
}

function chartLayout(yTitle, bars=false) {
  return {
    paper_bgcolor:'rgba(0,0,0,0)',
    plot_bgcolor:'rgba(0,0,0,0)',
    font:{color:'#edf2ff'},
    xaxis:{gridcolor:'rgba(255,255,255,.08)'},
    yaxis:{title:yTitle, gridcolor:'rgba(255,255,255,.08)'},
    barmode: bars ? 'group' : undefined,
    margin:{l:50,r:20,t:20,b:40},
    legend:{orientation:'h', y:1.12}
  };
}

function changeSub(v, base) {
  const delta = ((v - base) / Math.abs(base || 1));
  const sign = delta >= 0 ? '+' : '';
  return `${sign}${(delta*100).toFixed(1)}% vs prior year`;
}

function formatAssumptionValue(value, name) {
  if (name === 'CashFloor') return fmtB(value);
  if (['DSO','DIO','DPO'].includes(name)) return NUM1.format(value) + ' days';
  return fmtPct(value);
}

function statusClass(s) {
  const t = (s||'').toLowerCase();
  if (t.includes('pass')) return 'diag-pass';
  if (t.includes('warn')) return 'diag-warn';
  return 'diag-fail';
}

function deepClone(obj) {
  return JSON.parse(JSON.stringify(obj));
}

init();
